module top_module(
    input clk,
    input rst,
    input ena,
    input [15:0] data_in,
    output reg [15:0] data_out
);reg [15:0] reset_reg;

    always @(posedge clk) begin
        if (rst) begin
            reset_reg <= 16'b0;
        end else if (ena) begin
            reset_reg <= {reset_reg[14:0], data_in[0]};
        end
    end

    assign data_out = reset_reg;

endmodule
